import React, { useEffect, useState } from 'react';
import { View, Button, Alert } from 'react-native';
import { RNIap, purchaseUpdatedListener, purchaseErrorListener } from 'react-native-iap';

const paymentModule = () => {
  const [products, setProducts] = useState([]);
  const [isPurchaseInProgress, setIsPurchaseInProgress] = useState(false);

  useEffect(() => {
    const initIAP = async () => {
      try {
        await RNIap.initConnection();
        const productIds = ['product_id_1', 'product_id_2'];
        const availableProducts = await RNIap.getProducts(productIds);
        setProducts(availableProducts);
      } catch (err) {
        console.warn(err);
      }
    };

    initIAP();

    const purchaseUpdateSubscription = purchaseUpdatedListener((purchase) => {
      const receipt = purchase.transactionReceipt;
      if (receipt) {
        // Handle successful purchase
        Alert.alert('Purchase Successful', 'Thank you for your purchase!');
        setIsPurchaseInProgress(false);
      }
    });

    const purchaseErrorSubscription = purchaseErrorListener((error) => {
      Alert.alert('Purchase Error', error.message);
      setIsPurchaseInProgress(false);
    });

    return () => {
      purchaseUpdateSubscription.remove();
      purchaseErrorSubscription.remove();
      RNIap.endConnection();
    };
  }, []);

  const requestPurchase = async (productId) => {
    if (isPurchaseInProgress) return;
    setIsPurchaseInProgress(true);
    try {
      await RNIap.requestPurchase(productId);
    } catch (err) {
      Alert.alert('Purchase Failed', err.message);
      setIsPurchaseInProgress(false);
    }
  };

  return (
    <View>
      {products.map((product) => (
        <Button
          key={product.productId}
          title={`Buy ${product.title} - ${product.price}`}
          onPress={() => requestPurchase(product.productId)}
        />
      ))}
    </View>
  );
};

export default paymentModule;